import{_ as e,o as r,c as i,ae as a}from"./chunks/framework.RRduUuAx.js";const u=JSON.parse('{"title":"ADR-001: Use Ed25519 as Primary Signing Algorithm","description":"","frontmatter":{},"headers":[],"relativePath":"adrs/ADR-001-ed25519-primary.md","filePath":"adrs/ADR-001-ed25519-primary.md"}'),o={name:"adrs/ADR-001-ed25519-primary.md"};function s(n,t,d,l,c,h){return r(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="adr-001-use-ed25519-as-primary-signing-algorithm" tabindex="-1">ADR-001: Use Ed25519 as Primary Signing Algorithm <a class="header-anchor" href="#adr-001-use-ed25519-as-primary-signing-algorithm" aria-label="Permalink to &quot;ADR-001: Use Ed25519 as Primary Signing Algorithm&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> 2026-04-02<br><strong>Deciders:</strong> Architecture Team</p><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>We need to select a primary signing algorithm for token issuance. The options include RSA-based algorithms (RS256, RS384, RS512), ECDSA algorithms (ES256, ES384, ES512), and Edwards curve algorithms (Ed25519, Ed448).</p><p>Modern applications require:</p><ul><li>High performance signing and verification</li><li>Strong security properties</li><li>Small key sizes for efficient storage</li><li>Compatibility with modern cryptographic libraries</li></ul><hr><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We will use <strong>Ed25519</strong> as the primary signing algorithm for token issuance.</p><h3 id="justification" tabindex="-1">Justification <a class="header-anchor" href="#justification" aria-label="Permalink to &quot;Justification&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Algorithm</th><th>Key Size</th><th>Signature Size</th><th>Performance</th><th>Security Level</th></tr></thead><tbody><tr><td>RS256</td><td>2048 bits</td><td>256 bytes</td><td>Medium</td><td>112 bits</td></tr><tr><td>RS384</td><td>3072 bits</td><td>384 bytes</td><td>Slow</td><td>128 bits</td></tr><tr><td>RS512</td><td>4096 bits</td><td>512 bytes</td><td>Very Slow</td><td>128 bits</td></tr><tr><td>ES256</td><td>256 bits</td><td>64 bytes</td><td>Fast</td><td>128 bits</td></tr><tr><td>ES384</td><td>384 bits</td><td>96 bytes</td><td>Medium</td><td>192 bits</td></tr><tr><td>ES512</td><td>521 bits</td><td>132 bytes</td><td>Slow</td><td>256 bits</td></tr><tr><td><strong>Ed25519</strong></td><td>256 bits</td><td>64 bytes</td><td><strong>Very Fast</strong></td><td><strong>256 bits</strong></td></tr></tbody></table><p>Ed25519 provides:</p><ol><li><strong>Superior performance</strong> - 3x faster than RSA, comparable to ECDSA</li><li><strong>Small signatures</strong> - 64 bytes, same as ES256 but with higher security</li><li><strong>High security</strong> - 256-bit security level, equivalent to AES-256</li><li><strong>Side-channel resistance</strong> - Designed to be resistant to timing attacks</li><li><strong>Deterministic signatures</strong> - No ECDSA malleability issues</li><li><strong>Modern standard</strong> - Widely adopted in modern protocols (PASETO, WireGuard)</li></ol><h3 id="secondary-algorithm-support" tabindex="-1">Secondary Algorithm Support <a class="header-anchor" href="#secondary-algorithm-support" aria-label="Permalink to &quot;Secondary Algorithm Support&quot;">​</a></h3><ul><li><strong>RS256</strong> - Supported for legacy system compatibility</li><li><strong>ES256</strong> - Supported for environments requiring ECDSA</li><li><strong>PASETO v4</strong> - Full support for platform-agnostic security tokens</li></ul><hr><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Faster token operations across all endpoints</li><li>Reduced storage requirements for token data</li><li>Stronger cryptographic guarantees</li><li>Modern, future-proof cryptography</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Not compatible with systems requiring RSA certificates</li><li>Some legacy IdPs may not support Ed25519</li><li>Requires additional configuration for RSA-only environments</li></ul><h3 id="mitigation" tabindex="-1">Mitigation <a class="header-anchor" href="#mitigation" aria-label="Permalink to &quot;Mitigation&quot;">​</a></h3><ul><li>Provide RS256 as fallback for enterprise compatibility</li><li>Document interoperability requirements clearly</li><li>Consider EdDSA certificate chains for future upgrades</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://datatracker.ietf.org/doc/html/rfc8032" target="_blank" rel="noreferrer">RFC 8032 - EdDSA</a></li><li><a href="https://datatracker.ietf.org/doc/html/rfc8080" target="_blank" rel="noreferrer">RFC 8080 - Edwards-Curve Digital Security Algorithm</a></li><li><a href="https://ed25519.cr.yp.to/ed25519-20110701.pdf" target="_blank" rel="noreferrer">Bernstein et al. - Ed25519: High-speed high-security signatures</a></li></ul>',27)])])}const p=e(o,[["render",s]]);export{u as __pageData,p as default};
